/**
 * ──────────────────────────────────────────────────────────────────────────────
 * FLATTEN TICKTICK PROJECT  →  ONE-DIMENSIONAL TASK ARRAY
 * ──────────────────────────────────────────────────────────────────────────────
 */
const rows = $input.all();

/* ────────── user config injected by previous Set-node ────────── */
const USER_TZ   = $json.TICKTICK_TIMEZONE ?? 'Europe/Budapest';
const TZ_OFFSET = $json.TICKTICK_OFFSET  ?? '+0200'; 

/* ────────── helpers ────────── */
const pad = n => n.toString().padStart(2, '0');
function toTicktick(dateString, offset = TZ_OFFSET) {
  if (!dateString) return null;
  const d = new Date(dateString);
  return (
    d.getFullYear()               + '-' +
    pad(d.getMonth() + 1)         + '-' +
    pad(d.getDate())              + 'T' +
    pad(d.getHours())             + ':' +
    pad(d.getMinutes())           + ':' +
    pad(d.getSeconds())           +
    offset
  );
}

/* ────────── flatten everything ────────── */
const flat = rows.flatMap(item => {
  const pj        = item.json.project ?? {};
  const projectId   = pj.id   ?? 'N/A';
  const projectName = pj.name ?? 'N/A';

  const tasks = item.json.tasks ?? [];

  return tasks
    // ─── SZŰRÉS: csak nyitott, DUE-DATE-tel rendelkező taskok maradnak ───
    .filter(t => t.status !== 2 && t.dueDate)
    .flatMap(parent => {
      const base = {
        projectId,
        projectName,
        parentTaskId : parent.id,
        parentTitle  : parent.title,

        taskId    : parent.id,
        title     : parent.title,
        content   : parent.content ?? '',

        startDate : toTicktick(parent.startDate),
        dueDate   : toTicktick(parent.dueDate),  
        isAllDay : parent.isAllDay,
        timeZone  : USER_TZ,
        priority  : parent.priority,
        tags      : Array.isArray(parent.tags)
                      ? parent.tags.map(t => typeof t === 'string' ? t : (t.name ?? t))
                      : [],
        status    : parent.status,
        etag      : parent.etag,
      };

      // csak akkor adjuk tovább, ha tényleg van dueDate
      if (!base.dueDate) return [];

      const subs = Array.isArray(parent.items)
        ? parent.items.filter(s => s.status !== 2 && s.dueDate)
        : [];

      const subObjects = subs.map(sub => ({
        ...base,
        taskId    : sub.id,
        title     : sub.title,
        content   : sub.content ?? '',

        startDate : toTicktick(sub.startDate),
        dueDate   : toTicktick(sub.dueDate),


        priority  : sub.priority ?? parent.priority,
        status    : sub.status  ?? parent.status,
      }));

      return [base, ...subObjects];
    });
});

/* ────────── hand over to the next node ────────── */
return flat.map(row => ({ json: row }));

