// ──────────────────────────────────────────────────────────────────────────────
// Scheduling Node — JavaScript Implementation (timezone-aware via Luxon)

// 1) Read inputs
const items      = $input.all();
const configItem = items[0].json;
const rawTasks   = items.slice(1).map(i => i.json);

// 2) Unpack configuration
const {
  workSlots,
  PLAN_DAYS_AHEAD           = 1,
  DEFAULT_TASK_DURATION_MIN = 15,
  TASK_BUFFER_MIN           = 10,
  TIMEZONE,
  currentDate
} = configItem;

if (!TIMEZONE) {
  throw new Error('TIMEZONE missing from Defaults — set it to an IANA name like "Europe/Budapest"');
}

// 3) Helpers — every formatted timestamp is rendered in TIMEZONE (TickTick rejects ms)
function fmt(jsDate) {
  return DateTime.fromJSDate(jsDate)
    .setZone(TIMEZONE)
    .toFormat("yyyy-MM-dd'T'HH:mm:ssZZZ");
}

// Local weekday name without depending on container/system locale
const WEEKDAYS = ['', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'];

// 4) Determine now, cursor, and window end — all in TIMEZONE
const nowDt = currentDate
  ? DateTime.fromISO(String(currentDate), { zone: TIMEZONE })
  : DateTime.now().setZone(TIMEZONE);

const tenMin = 10 * 60 * 1000;
const firstCursorDt = DateTime.fromMillis(
  Math.ceil(nowDt.toMillis() / tenMin) * tenMin,
  { zone: TIMEZONE }
);

const todayMidDt  = nowDt.startOf('day');
const windowEndDt = todayMidDt.plus({ days: PLAN_DAYS_AHEAD - 1 }).endOf('day');

// JS Date counterparts (busyPeriods arithmetic uses plain Dates)
const now         = nowDt.toJSDate();
const firstCursor = firstCursorDt.toJSDate();
const todayMid    = todayMidDt.toJSDate();
const windowEnd   = windowEndDt.toJSDate();

// 5) Prepare tasks
const tasks = rawTasks.map(t => ({ ...t, done: false, allDay: false }));
tasks.forEach(t => {
  // Only dueDate is required: it anchors the task in time for sorting.
  // startDate is rewritten on placement (or normalized to midnight for leftovers),
  // so its absence is fine.
  t.exclude = !t.dueDate || (t.tags || []).includes('dfix');
});
let toSchedule = tasks.filter(t => !t.exclude && new Date(t.dueDate) <= windowEnd);

// 6) Sort tasks: overdue → today → future, with priority within each group
toSchedule.sort((a, b) => {
  const da = new Date(a.dueDate), db = new Date(b.dueDate);
  function group(d) {
    if (d < now) return 0;
    const dDay = DateTime.fromJSDate(d).setZone(TIMEZONE).startOf('day');
    return +dDay === +todayMidDt ? 1 : 2;
  }
  const ga = group(da), gb = group(db);
  if (ga !== gb) return ga - gb;
  if (ga < 2) return (b.priority || 0) - (a.priority || 0);
  return da - db;
});

// 7) Normalize dueDates to midnight in TIMEZONE and mark all-day
toSchedule.forEach(t => {
  const midnightStr = DateTime.fromISO(t.dueDate, { zone: TIMEZONE })
    .startOf('day')
    .toFormat("yyyy-MM-dd'T'HH:mm:ssZZZ");
  t.startDate = midnightStr;
  t.dueDate   = midnightStr;
  t.allDay    = true;
});

// 8) Build raw work slots — built in TIMEZONE so DST is handled correctly
const allSlots = [];
for (let day = 0; day < PLAN_DAYS_AHEAD; day++) {
  const dayDt = todayMidDt.plus({ days: day });
  const wd = WEEKDAYS[dayDt.weekday];
  (workSlots[wd] || []).forEach(([s, e]) => {
    const [sh, sm] = s.split(':').map(Number);
    const [eh, em] = e.split(':').map(Number);
    let ssDt = dayDt.set({ hour: sh, minute: sm, second: 0, millisecond: 0 });
    let seDt = dayDt.set({ hour: eh, minute: em, second: 0, millisecond: 0 });
    if (day === 0) {
      if (seDt <= firstCursorDt) return;
      if (ssDt < firstCursorDt) ssDt = firstCursorDt;
    }
    if (ssDt < seDt) {
      allSlots.push({ start: ssDt.toJSDate(), end: seDt.toJSDate() });
    }
  });
}

const rawSlots = allSlots.map(s => ({ start: s.start, end: s.end }));

// 9) Collect busy periods (Google free/busy + dfix tasks treated as busy)
const busyInput = items.find(i => i.json.kind === 'calendar#freeBusy');
const googleBusy = [];
if (busyInput) {
  Object.values(busyInput.json.calendars || {}).forEach(cal =>
    (cal.busy || []).forEach(b => googleBusy.push({ start: new Date(b.start), end: new Date(b.end) }))
  );
}

const dfixBusy = tasks
  .filter(
    t =>
      (t.tags || []).includes('dfix') &&
      t.startDate && t.dueDate &&
      t.isAllDay === false
  )
  .map(t => {
    const sb = new Date(t.startDate);
    const eb = new Date(t.dueDate);
    const start = sb < now ? now : sb;
    const end = eb > windowEnd ? windowEnd : eb;
    return { start, end };
  });

const busyPeriods = [...googleBusy, ...dfixBusy].sort((a, b) => a.start - b.start);

const googleBusyDebug   = googleBusy.map(b => ({ start: b.start, end: b.end }));
const dfixBusyDebug     = dfixBusy.map(b => ({ start: b.start, end: b.end }));
const busyPeriodsDebug  = busyPeriods.map(b => ({ start: b.start, end: b.end }));

// 10) Subtract busy periods from work slots → free slots
const free = allSlots.reduce((acc, slot) => {
  let cur = slot.start;
  busyPeriods.filter(b => b.end > slot.start && b.start < slot.end)
    .forEach(b => {
      if (b.start > cur) acc.push({ start: cur, end: b.start });
      cur = new Date(Math.max(cur.getTime(), b.end.getTime()));
    });
  if (cur < slot.end) acc.push({ start: cur, end: slot.end });
  return acc;
}, []);
const freeSlots = free.map(f => ({ start: f.start, end: f.end }));

// 11) Place tasks into free slots
const scheduled = [];
for (const task of toSchedule) {
  let dur = DEFAULT_TASK_DURATION_MIN;
  const ttag = (task.tags || []).find(x => /^d(\d+)$/.test(x));
  if (ttag) dur = parseInt(ttag.match(/^d(\d+)$/)[1], 10);
  task.allDay = false;
  for (const fs of free) {
    if ((fs.end - fs.start) / 60000 >= dur + TASK_BUFFER_MIN) {
      const startStr   = fmt(fs.start);
      const dueDateObj = new Date(fs.start.getTime() + dur * 60000);
      const dueStr     = fmt(dueDateObj);
      task.startDate = startStr;
      task.dueDate   = dueStr;
      task.allDay    = false;
      task.done      = true;
      fs.start       = new Date(dueDateObj.getTime() + TASK_BUFFER_MIN * 60000);
      break;
    }
  }
  scheduled.push(task);
}

const scheduledDebug = scheduled.map(t => ({ taskId: t.taskId, startDate: t.startDate, dueDate: t.dueDate, done: t.done, allDay: t.allDay }));

// 11.5) Leftover tasks become all-day on the last day of the planning window
const lastMidStr = todayMidDt
  .plus({ days: PLAN_DAYS_AHEAD - 1 })
  .toFormat("yyyy-MM-dd'T'HH:mm:ssZZZ");
scheduled.forEach(t => {
  if (!t.done) {
    t.startDate = lastMidStr;
    t.dueDate   = lastMidStr;
    t.allDay    = true;
  }
});

// 12) Production return
return scheduled.map(t => ({ json: t }));
